import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const compiledSourcePath = path.join(root, "dist", "src", "trust-panel", "surface-trust-panel.js");
const generatedPath = path.join(root, "src", "trust-panel", "trust-panel-module.generated.ts");
const checkOnly = process.argv.includes("--check");

const compiledSource = await readFile(compiledSourcePath, "utf8");

const generated = [
  "// Generated by scripts/build-trust-panel-module.mjs from dist/src/trust-panel/surface-trust-panel.js.",
  "// Do not edit directly; edit src/trust-panel/surface-trust-panel.ts and run npm run build:trust-panel-module.",
  "/* eslint-disable */",
  `export const TRUST_PANEL_JS: string = ${JSON.stringify(compiledSource)};`,
  "",
].join("\n");

if (checkOnly) {
  const currentGenerated = await readFile(generatedPath, "utf8").catch(() => "");
  if (currentGenerated !== generated) {
    throw new Error(
      "Trust panel module is out of sync. Run npm run build:trust-panel-module (after npm run build).",
    );
  }
  console.log("Trust panel generated module is synced.");
} else {
  await mkdir(path.dirname(generatedPath), { recursive: true });
  await writeFile(generatedPath, generated);
  console.log("Built trust panel generated module.");
}
